import{_ as e,o as r,c as i,ah as t}from"./chunks/framework.BNo2o5Ln.js";const m=JSON.parse('{"title":"Elasticsearch 实现原理","description":"","frontmatter":{"title":"Elasticsearch 实现原理","order":3},"headers":[],"relativePath":"server/nosql/es.md","filePath":"server/nosql/es.md"}'),n={name:"server/nosql/es.md"};function s(l,a,h,o,c,d){return r(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="elasticsearch-实现原理" tabindex="-1">Elasticsearch 实现原理 <a class="header-anchor" href="#elasticsearch-实现原理" aria-label="Permalink to “Elasticsearch 实现原理”">​</a></h1><p>Elasticsearch 是基于 Lucene 的分布式搜索引擎，专注于全文检索和日志分析。理解 Elasticsearch 的实现，需要深入倒排索引、分片架构、分布式协调和查询处理。</p><h2 id="倒排索引" tabindex="-1">倒排索引 <a class="header-anchor" href="#倒排索引" aria-label="Permalink to “倒排索引”">​</a></h2><h3 id="倒排索引结构" tabindex="-1">倒排索引结构 <a class="header-anchor" href="#倒排索引结构" aria-label="Permalink to “倒排索引结构”">​</a></h3><p>正排索引是文档到词的映射（文档包含哪些词），倒排索引是词到文档的映射（哪些文档包含这个词）。倒排索引包含：Term Dictionary（词项字典）、Posting List（倒排表）、Term Frequency &amp; Position（词频和位置）。</p><p>Term Dictionary 是所有词的有序列表，支持快速查找。Posting List 是包含该词的文档 ID 列表，支持布尔查询。词频用于相关性评分，位置用于短语查询和邻近查询。</p><h3 id="fst-压缩" tabindex="-1">FST 压缩 <a class="header-anchor" href="#fst-压缩" aria-label="Permalink to “FST 压缩”">​</a></h3><p>Term Dictionary 使用 FST（Finite State Transducer）压缩，FST 是一种有限状态自动机，共享前缀和后缀，极大压缩空间。FST 支持 O(len(term)) 的查找，比二分查找更快。FST 还支持映射，可以存储额外的信息（如文档频率）。</p><h3 id="posting-list-压缩" tabindex="-1">Posting List 压缩 <a class="header-anchor" href="#posting-list-压缩" aria-label="Permalink to “Posting List 压缩”">​</a></h3><p>Posting List 是递增的整数数组，可以使用 Frame of Reference（FOR）压缩：将差分（gap）编码，然后按位存储。例如 [100, 101, 105] 压缩为 [100, 1, 4]，差分值小可以用更少的位存储。</p><p>跳表（Skip List）加速 Posting List 的交集和并集：每 n 个节点存储一个跳转指针，可以快速跳过不匹配的文档。</p><h3 id="相关性评分" tabindex="-1">相关性评分 <a class="header-anchor" href="#相关性评分" aria-label="Permalink to “相关性评分”">​</a></h3><p>BM25 算法是默认的评分算法，基于词频（TF）、文档频率（IDF）、字段长度归一化。TF 越高分数越高，IDF 越高分数越高，字段长度越短分数越高。BM25 对词频有饱和效应，避免高频词主导分数。</p><h2 id="分片架构" tabindex="-1">分片架构 <a class="header-anchor" href="#分片架构" aria-label="Permalink to “分片架构”">​</a></h2><h3 id="索引与分片" tabindex="-1">索引与分片 <a class="header-anchor" href="#索引与分片" aria-label="Permalink to “索引与分片”">​</a></h3><p>索引是文档的逻辑集合，分片是索引的物理划分。每个索引可以分成多个主分片（primary shard），每个主分片可以有多个副本分片（replica shard）。主分片数创建后不能修改，副本分片数可以动态调整。</p><p>文档路由：根据文档 ID 计算分片编号，shard = hash(_id) % number_of_primary_shards。然后路由到对应分片，由分片所在的节点处理。</p><h3 id="segment" tabindex="-1">Segment <a class="header-anchor" href="#segment" aria-label="Permalink to “Segment”">​</a></h3><p>分片包含多个 Segment（段），每个段是不可变的索引文件。写入文档时，先写入内存 buffer，buffer 满或 refresh 后生成新段。段不可变，更新和删除是标记删除，添加新文档到新段。段合并（merge）将多个段合并成更大的段，清理删除的文档，减少段数量。</p><h3 id="near-real-time" tabindex="-1">Near Real-Time <a class="header-anchor" href="#near-real-time" aria-label="Permalink to “Near Real-Time”">​</a></h3><p>refresh 默认每 1 秒执行一次，将内存 buffer 写入新段，新段对搜索可见。这是 Elasticsearch 近实时的原因。flush 将段写入磁盘，清空内存 buffer，生成 commit point。translog 记录所有操作，flush 后可以删除旧的 translog。</p><p>translog 保证持久性：每次写操作先写入 translog（fsync），然后写入内存 buffer。崩溃后重放 translog 恢复未 flush 的数据。translog 可以配置为 async（每 5 秒写一次），但可能丢失数据。</p><h2 id="分布式协调" tabindex="-1">分布式协调 <a class="header-anchor" href="#分布式协调" aria-label="Permalink to “分布式协调”">​</a></h2><h3 id="集群拓扑" tabindex="-1">集群拓扑 <a class="header-anchor" href="#集群拓扑" aria-label="Permalink to “集群拓扑”">​</a></h3><p>集群由多个节点组成，节点通过 cluster.name 加入集群。节点角色：Master-eligible（可当选主节点）、Data（存储数据）、Ingest（预处理数据）、Coordinating（协调查询）。一个节点可以同时扮演多个角色。</p><p>主节点负责集群状态管理（创建删除索引、分片分配、节点加入退出）。主节点通过 cluster.state 更新集群状态，然后发布到所有节点。集群状态持久化到全局集群状态（不是每个节点都持久化）。</p><h3 id="故障检测" tabindex="-1">故障检测 <a class="header-anchor" href="#故障检测" aria-label="Permalink to “故障检测”">​</a></h3><p>节点定期 ping 其他节点，如果超时未响应，标记为故障。主节点故障时，从节点选举新主节点。选举使用 Raft 类似的算法：候选节点请求投票，多数节点同意则当选主节点。</p><p>脑裂（Split Brain）是两个节点都认为自己是主节点，导致集群状态不一致。防止脑裂：minimum_master_nodes 设置为 (master_eligible_nodes / 2) + 1，保证多数派才能当选主节点。Elasticsearch 7+ 默认使用投票配置，自动处理。</p><h3 id="分片分配" tabindex="-1">分片分配 <a class="header-anchor" href="#分片分配" aria-label="Permalink to “分片分配”">​</a></h3><p>主节点决定分片分配到哪些节点，考虑因素：磁盘空间、分片数量、节点角色、用户规则。分片可以自动迁移，平衡负载。节点退出时，分片迁移到其他节点。节点加入时，其他节点迁移分片到新节点。</p><h2 id="查询处理" tabindex="-1">查询处理 <a class="header-anchor" href="#查询处理" aria-label="Permalink to “查询处理”">​</a></h2><h3 id="查询类型" tabindex="-1">查询类型 <a class="header-anchor" href="#查询类型" aria-label="Permalink to “查询类型”">​</a></h3><p>查询分为两种：Query Context（查询上下文）和 Filter Context（过滤上下文）。Query Context 计算相关性评分，Filter Context 不计算评分（只判断是否匹配）。Filter 缓存结果，性能更好。</p><p>查询类型：match（全文查询，分词后查询）、term（精确查询，不分词）、range（范围查询）、bool（布尔查询，组合多个查询）、function_score（自定义评分）。</p><h3 id="查询执行" tabindex="-1">查询执行 <a class="header-anchor" href="#查询执行" aria-label="Permalink to “查询执行”">​</a></h3><p>客户端发送查询到任意节点（coordinating node），coordinating node 将查询发送到相关分片，每个分片本地执行查询，返回结果给 coordinating node，coordinating node 合并排序，返回最终结果。</p><p>分散查询（scatter-gather）：查询发送到所有分片，即使结果只有一个分片有。这是由于文档路由是 hash(_id)，查询条件可能包含其他字段，无法路由。</p><p>偏好查询（preference）：指定查询某个分片的副本，可以利用缓存。例如 _local（本地节点）、_primary（主分片）、cookie（用户一致性）。</p><h3 id="聚合" tabindex="-1">聚合 <a class="header-anchor" href="#聚合" aria-label="Permalink to “聚合”">​</a></h3><p>聚合分为 Bucket（桶聚合，分组）、Metric（指标聚合，计算统计值）、Pipeline（管道聚合，基于其他聚合结果）、Matrix（矩阵聚合，多维度分析）。</p><p>聚合在分片本地执行，coordinating node 合并结果。某些聚合需要分散到所有分片，某些聚合可以优化。例如 cardinality（去重计数）使用 HyperLogLog 算法，可以分布式计算。</p><h2 id="性能优化" tabindex="-1">性能优化 <a class="header-anchor" href="#性能优化" aria-label="Permalink to “性能优化”">​</a></h2><h3 id="索引设计" tabindex="-1">索引设计 <a class="header-anchor" href="#索引设计" aria-label="Permalink to “索引设计”">​</a></h3><p>字段类型选择：keyword 适合精确匹配和聚合，text 适合全文检索。避免过多字段，可以使用 nested 或 object 类型。动态映射可能推断错误，建议显式定义 mapping。</p><h3 id="分片策略" tabindex="-1">分片策略 <a class="header-anchor" href="#分片策略" aria-label="Permalink to “分片策略”">​</a></h3><p>分片大小建议 10-50GB，过小导致分片数量多，过大会导致恢复慢。分片数量建议不超过节点数 × 2，避免分片分配开销。时间序列索引可以按时间创建索引，例如 logs-2023-01-01，定期删除旧索引。</p><h3 id="查询优化" tabindex="-1">查询优化 <a class="header-anchor" href="#查询优化" aria-label="Permalink to “查询优化”">​</a></h3><p>使用 filter context 代替 query context，利用缓存。避免深度分页（from + size 大于 10000），使用 scroll 或 search_after。避免 wildcard 查询前缀通配符，会扫描所有文档。避免 script 查询，性能差。</p><p>Elasticsearch 是强大的搜索引擎，适合日志分析、全文检索、指标监控。理解它的实现，有助于设计索引、优化查询和规划集群架构。</p>',50)])])}const f=e(n,[["render",s]]);export{m as __pageData,f as default};
